{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This reaction is a classic textbook example of the Ritter reaction, demonstrating the formation of a stable tertiary carbocation from tert-butanol under strong acid (sulfuric acid) catalysis. This carbocation is then trapped by a simple nitrile (acetonitrile) to form a nitrilium ion, which upon hydrolysis yields the corresponding N-tert-butylacetamide. All components are simple, acyclic, and clearly illustrate the core transformation of the Ritter reaction.",
    "collision_avoidance_note": "The use of a simple tertiary alcohol (tert-butanol) and a simple nitrile (acetonitrile) avoids complex structures that could overlap with other named reactions. It specifically avoids arenes (Friedel-Crafts), alkenes (Prins, Markovnikov addition), or other functional groups that might trigger unrelated reaction family classifications. The transformation is a clear C-N bond formation to create an amide from a carbocation source and a nitrile, which is the defining feature of the Ritter reaction."
  }
}
